module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

    reg [3:0] mul_en_out_reg;
    reg [3:0] mul_en_out_next;
    reg [7:0] mul_a_reg;
    reg [7:0] mul_b_reg;
    reg [15:0] temp[0:7];
    reg [15:0] sum[0:3];
    reg [15:0] mul_out_reg;
    reg [15:0] mul_out_next;
    integer i;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_en_out_reg <= 4'd0;
        end
        else begin
            mul_en_out_reg <= mul_en_out_next;
        end
    end
    always @(*) begin
        case(mul_en_out_reg)
            4'd0: mul_en_out_next = {3'd0,mul_en_in};
            4'd1: mul_en_out_next = 4'd2;
            4'd2: mul_en_out_next = 4'd3;
            default: mul_en_out_next = 4'd0;
        endcase
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_a_reg <= 8'd0;
            mul_b_reg <= 8'd0;
        end
        else begin
            case(mul_en_out_reg)
                4'd0: begin
                    mul_a_reg <= mul_a;
                    mul_b_reg <= mul_b;
                end
                default: begin
                    mul_a_reg <= 8'd0;
                    mul_b_reg <= 8'd0;
                end
            endcase
        end
    end
    always @(*) begin
        for(i = 0; i < 8; i = i + 1) begin
            if(i < 4) begin
                temp[i] = {8{mul_b_reg[i]}} & mul_a_reg;
            end
            else begin
                temp[i] = 16'b0;
            end
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum[0] <= 16'd0;
            sum[1] <= 16'd0;
            sum[2] <= 16'd0;
            sum[3] <= 16'd0;
        end
        else begin
            sum[0] <= temp[0] + temp[1];
            sum[1] <= temp[2] + temp[3];
            sum[2] <= temp[4] + temp[5];
            sum[3] <= temp[6] + temp[7];
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out_reg <= 16'd0;
        end
        else begin
            mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_en_out <= 1'b0;
        end
        else begin
            mul_en_out <= mul_en_out_reg[3];
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out <= 16'd0;
        end
        else begin
            mul_out <= mul_en_out_reg[3]?mul_out_reg:16'd0;
        end
    end
endmodule
